78	  // Outside writer (e.g. QEMU side) places known bytes via the same mapping.
79	  backing.span()[0x200] = 0xca;
80	  backing.span()[0x201] = 0xfe;
81	
82	  SimpleMemory<32> mem{
83	    "mem", MemoryRegion{kBase, kBase + kSize - 1},
84	    MemoryRegion{SimpleMemory<32>::INVALID_ADDRESS,
85	                 SimpleMemory<32>::INVALID_ADDRESS},
86	    backing.span()};
87	
88	  std::array<uint8_t, 2> bytes{};
89	  tlm::tlm_generic_payload gp;
90	  gp.set_command(tlm::TLM_READ_COMMAND);
91	  gp.set_address(kBase + 0x200);
92	  gp.set_data_ptr(bytes.data());
93	  gp.set_data_length(bytes.size());
94	  gp.set_response_status(tlm::TLM_INCOMPLETE_RESPONSE);
95	  sc_core::sc_time delay = sc_core::SC_ZERO_TIME;
96	  mem.b_transport(gp, delay);
97	  REQUIRE(gp.get_response_status() == tlm::TLM_OK_RESPONSE);
98	
99	  CHECK(bytes[0] == 0xca);
100	  CHECK(bytes[1] == 0xfe);
101	  std::filesystem::remove(path);
102	}
